def longest_common_prefix(strs):
    if not strs:
        return ""

    # Find the shortest string in strs, which will be the upper limit of our prefix length
    shortest = min(strs, key=len)

    for i, char in enumerate(shortest):
        for other in strs:
            if other[i] != char:
                # Found a mismatch, return the prefix up to this point
                return shortest[:i]

    # If we didn't find any mismatches, the whole shortest string is the common prefix
    return shortest
