    if not strs:
        return ""

    # Find the shortest string in strs, which will be the upper bound of the common prefix length.
    shortest = min(strs, key=len)

    for i, char in enumerate(shortest):
        for other in strs:
            if other[i] != char:
                # If a mismatch is found, return the substring from start to the current index (exclusive).
                return shortest[:i]

    # If no mismatches are found, the entire shortest string is the common prefix.
